const actions = $input.all().map(i => i.json);

const categorized = {
  overdue: [],
  dueToday: [],
  dueIn3Days: [],
  dueThisWeek: [],
  byOwner: {}
};

for (const action of actions) {
  const daysDiff = action.property_days_until_due;
  if (daysDiff === undefined || daysDiff === null) continue; // Skip if missing

  const ownerId = action.property_owner || 'Unassigned';

  const actionData = {
    id: action.id,
    url: action.url,
    title: action.name || 'Untitled',
    dueDate: action.property_due_date?.start || null,
    priority: action.property_priority || 'P3 Normal',
    status: action.property_status || 'Open',
    projectName: action.property_projects_name || null,
    dueInday : action.property_days_until_due
  };

  // Categorize by days until due
  if (daysDiff < 0) categorized.overdue.push(actionData);
  else if (daysDiff === 0) categorized.dueToday.push(actionData);
  else if (daysDiff <= 3) categorized.dueIn3Days.push(actionData);
  else if (daysDiff <= 7) categorized.dueThisWeek.push(actionData);

  // Group by owner
  const ownerGroup = categorized.byOwner[ownerId] ??= {
    ownerName: ownerId,
    actions: []
  };
  ownerGroup.actions.push(actionData);
}

return [{ json: categorized }];

const categorized = $input.first().json;
const results = [];

for (const [ownerId, ownerData] of Object.entries(categorized.byOwner)) {
  // Skip unassigned
  if (!ownerId || ownerId.toLowerCase() === 'unassigned') continue;

  const ownerActions = ownerData.actions;

  // Now filters will work because daysDiff exists
  const overdue = ownerActions.filter(a => a.dueInday < 0);
  const dueToday = ownerActions.filter(a => a.dueInday === 0);
  const dueIn3Days = ownerActions.filter(a => a.dueInday > 0 && a.dueInday <= 3);
  const dueThisWeek = ownerActions.filter(a => a.dueInday > 3 && a.dueInday <= 7);

  if (ownerActions.length > 0) {
    results.push({
      json: {
        ownerEmail: ownerId, // use ownerId as email
        ownerName: ownerData.ownerName || ownerId,
        overdue,
        dueToday,
        dueIn3Days,
        dueThisWeek,
        totalActions: ownerActions.length
      }
    });
  }
}

return results;

